/* ===== STORE v2 (SSOT — Single Source of Truth) ===== */
const HT = {
  state: {
    currentPairAddress: null,
    requestId: 0,
    wsStatus: 'disconnected',
    // Price cache — keyed by token address
    priceCache: {},
    // Overview metadata (mcap, liq, vol — NOT price)
    overview: {},
    // Candles by timeframe
    candles: { '1m': [], '5m': [], '15m': [], '1h': [], '4h': [], '1d': [] },
    // Trades (store 200, UI shows 50)
    trades: [],
    // Pair info (dynamic + static)
    pairDynamic: null,
    pairStatic: {},
    // Control
    timeframe: '1h',
    scaleMode: 'log',
    chartType: 'candle',
    loading: false,
    subscriptions: new Set()
  },
  controller: null,
  _priceScheduled: false,
  _tradeScheduled: false,
  _chartScheduled: false
};

/* ===== DISPATCH — one-way data flow ===== */
function dispatch(action) {
  const st = HT.state;
  switch (action.type) {
    case 'SELECT_PAIR':
      st.currentPairAddress = action.address;
      st.candles = { '1m': [], '5m': [], '15m': [], '1h': [], '4h': [], '1d': [] };
      st.trades = [];
      st.pairDynamic = null;
      st.pairStatic = {};
      break;

    case 'SET_PRICE':
      st.priceCache[action.address] = {
        eth: action.priceEth,
        usd: action.priceUsd || (action.priceEth * ethPriceUsd),
        updatedAt: action.updatedAt || Date.now()
      };
      break;

    case 'SET_CANDLES':
      st.candles[action.timeframe] = action.data || [];
      break;

    case 'SET_TRADES':
      st.trades = action.data || [];
      break;

    case 'NEW_TRADE':
      {
        // swap = [timestamp, side, tokenAmt, ethAmt, priceEth, txHash, sender, token0, token1]
        const swap = action.data;
        st.trades.unshift(swap);
        if (st.trades.length > 200) st.trades.length = 200;

        const addr = (st.currentPairAddress || '').toLowerCase();
        if (!addr) break;

        // Only update if swap belongs to current token
        const t0 = ((swap[7] || '') + '').toLowerCase();
        const t1 = ((swap[8] || '') + '').toLowerCase();
        if (t0 !== addr && t1 !== addr) break;

        const priceEth = swap[4] || 0;
        const swapTs = swap[0] || 0;

        // Update price cache
        st.priceCache[addr] = {
          eth: priceEth,
          usd: priceEth * ethPriceUsd,
          updatedAt: swapTs ? swapTs * 1000 : Date.now()
        };

        // Update current candle — pass object for updateCurrentCandle
        updateCurrentCandle({ timestamp: swapTs, priceEth: priceEth, amountEth: swap[3] || 0 });

        schedulePriceRender();
        scheduleTradeRender();
        scheduleChartRender();
      }
      break;

    case 'SET_OVERVIEW':
      st.overview[action.address] = {
        marketCap: action.marketCap,
        liquidity: action.liquidity,
        volume: action.volume,
        holders: action.holders,
        created: action.created,
        symbol: action.symbol
      };
      break;

    case 'SET_PAIR_DYNAMIC':
      st.pairDynamic = action.data;
      break;

    case 'SET_PAIR_STATIC':
      st.pairStatic[action.address] = action.data;
      break;
  }
}

/* ===== BUCKET TIME HELPER ===== */
function bucketTime(timestamp, timeframe) {
  const sec = ({ '1m': 60, '5m': 300, '15m': 900, '1h': 3600, '4h': 14400, '1d': 86400 })[timeframe] || 3600;
  return Math.floor(timestamp / sec) * sec;
}

function updateCurrentCandle(swap) {
  const st = HT.state;
  const candles = st.candles[st.timeframe];
  const swapTs = swap.timestamp || (Date.now() / 1000);
  const bucket = bucketTime(swapTs, st.timeframe);
  const priceEth = swap.priceEth || 0;
  const volEth = Math.abs(swap.amountEth || 0);

  // Guard: skip invalid or extreme outlier prices
  if (priceEth <= 0) return;
  if (candles.length) {
    const lastClose = candles[candles.length - 1].close;
    if (lastClose > 0 && (priceEth / lastClose > 10 || priceEth / lastClose < 0.1)) return; // >10x spike or <10% crash = outlier
  }

  if (!candles.length || candles[candles.length - 1].time < bucket) {
    // New bucket
    candles.push({
      time: bucket,
      open: priceEth,
      high: priceEth,
      low: priceEth,
      close: priceEth,
      volume: volEth,
      trades: 1
    });
  } else {
    // Update current bucket
    const last = candles[candles.length - 1];
    last.high = Math.max(last.high, priceEth);
    last.low = Math.min(last.low, priceEth);
    last.close = priceEth;
    last.volume += volEth;
    last.trades++;
  }
}

/* ===== PARTIAL RENDERERS ===== */
function schedulePriceRender() {
  if (HT._priceScheduled) return;
  HT._priceScheduled = true;
  requestAnimationFrame(() => {
    HT._priceScheduled = false;
    updateTokenHeader();
  });
}

function scheduleTradeRender() {
  if (HT._tradeScheduled) return;
  HT._tradeScheduled = true;
  requestAnimationFrame(() => {
    HT._tradeScheduled = false;
    if (HT.state.trades.length) renderTrades(HT.state.trades.slice(0, 50));
  });
}

function scheduleChartRender() {
  if (HT._chartScheduled) return;
  HT._chartScheduled = true;
  requestAnimationFrame(() => {
    HT._chartScheduled = false;
    const candles = HT.state.candles[HT.state.timeframe];
    if (!candles.length || !mainS) return;
    // Update only the last candle — apply same convertFactor as renderCandlesToChart
    var last = candles[candles.length - 1];
    var cf = priceUnit === 'usd' ? ethPriceUsd : 1;
    mainS.update({ time: last.time, open: last.open * cf, high: last.high * cf, low: last.low * cf, close: last.close * cf });
  });
}
