/* ===== FORMATTERS ===== */
function fmtP(p) {
  if (!p || p === 0) return '$0.00';
  if (p >= 1) return '$' + p.toFixed(4);
  if (p >= 0.01) return '$' + p.toFixed(5);
  if (p >= 0.0001) return '$' + p.toFixed(7);
  if (p >= 0.000001) return '$' + p.toFixed(9);
  return '$' + p.toExponential(3);
}
function fmtC(n) {
  if (!n || n === 0) return '$0';
  if (n >= 1e9) return '$' + (n / 1e9).toFixed(2) + 'B';
  if (n >= 1e6) return '$' + (n / 1e6).toFixed(2) + 'M';
  if (n >= 1e3) return '$' + (n / 1e3).toFixed(2) + 'K';
  return '$' + n.toFixed(2);
}
function fmtE(n) {
  if (!n || n === 0) return '0';
  if (n >= 1000) return (n / 1000).toFixed(2) + 'K';
  if (n >= 1) return n.toFixed(4);
  if (n >= 0.01) return n.toFixed(4);
  return n.toExponential(3);
}
function fmtN(n, d) { if (d === undefined) d = 2; if (!n || n === 0) return '0'; if (n >= 1e9) return (n / 1e9).toFixed(d) + 'B'; if (n >= 1e6) return (n / 1e6).toFixed(d) + 'M'; if (n >= 1e3) return (n / 1e3).toFixed(d) + 'K'; return n.toFixed(d); }
function fmtPct(p) { if (p === undefined || p === null) return '\u2014'; return (p >= 0 ? '+' : '') + p.toFixed(2) + '%'; }
function fmtEth(n) { if (!n || n === 0) return '0'; if (n >= 1000) return (n / 1000).toFixed(1) + 'K'; if (n >= 1) return n.toFixed(2); if (n >= 0.01) return n.toFixed(4); return n.toExponential(3); }
function fmtT(n) { if (!n || n === 0) return '0'; if (n >= 1e9) return (n / 1e9).toFixed(2) + 'B'; if (n >= 1e6) return (n / 1e6).toFixed(2) + 'M'; if (n >= 1e3) return (n / 1e3).toFixed(2) + 'K'; return n.toFixed(2); }
function sA(a) { return a ? a.slice(0, 6) + '...' + a.slice(-4) : '\u2014'; }
function fmtTm(ts) {
  var s = typeof ts === "string" ? Math.floor((Date.now() - new Date(ts).getTime()) / 1000) : Math.floor((Date.now() - ts * 1000) / 1000);
  if (s < 0) s = 0;
  if (s < 60) return s + "s ago";
  var m = Math.floor(s / 60);
  if (m < 60) { var sec = s % 60; return sec ? m + "m " + sec + "s ago" : m + "m ago"; }
  var h = Math.floor(m / 60);
  if (h < 24) { var rm = m % 60; return rm ? h + "h " + rm + "m ago" : h + "h ago"; }
  var d = Math.floor(h / 24);
  if (d < 30) { var rh = h % 24; return rh ? d + "d " + rh + "h ago" : d + "d ago"; }
  return new Date(typeof ts === "string" ? ts : ts * 1000).toLocaleDateString("en-US", { month: "short", day: "numeric" });
}
function ipfsUrl(logo) {
  if (!logo) return null;
  if (logo.startsWith('http')) return logo;
  if (logo.startsWith('ipfs://')) return IPFS_GATEWAYS[0] + logo.slice(7);
  return null;
}

/* ===== PRICE UNIT (ETH/USD toggle) ===== */
let priceUnit = localStorage.getItem('hoodPriceUnit') || 'usd'; // 'eth' or 'usd'
function fmtPrice(priceEth) {
  if (priceUnit === 'usd') return fmtP(priceEth * ethPriceUsd);
  return priceEth.toExponential(4) + ' ETH';
}
function fmtMcap(mcEth) {
  if (priceUnit === 'usd') return fmtC(mcEth * ethPriceUsd);
  return fmtEth(mcEth) + ' ETH';
}
function fmtVol(volEth) {
  if (priceUnit === 'usd') return fmtC(volEth * ethPriceUsd);
  return fmtEth(volEth) + ' ETH';
}

