/* ===== TOKEN NORMALIZER ===== */
function normToken(t) {
  return {
    a: t.address, s: t.symbol, n: t.name, v: t.version || '',
    p: t.pairAddress || t.officialPool || '',
    price: t.priceUsd || (t.priceEth ? t.priceEth * ethPriceUsd : 0),
    priceEth: t.priceEth || (t.priceUsd ? t.priceUsd / ethPriceUsd : 0),
    ch: t.change24h !== undefined ? t.change24h : (t.priceChange6hPct || 0),
    mc: t.marketCapUsd || (t.marketCapEth ? t.marketCapEth * ethPriceUsd : 0),
    mcEth: t.marketCapEth || (t.marketCapUsd ? t.marketCapUsd / ethPriceUsd : 0),
    liq: t.liquidityUsd || 0,
    liqEth: t.liquidityUsd ? t.liquidityUsd / ethPriceUsd : 0,
    vol: t.volume24hUsd || (t.volume24hEth ? t.volume24hEth * ethPriceUsd : 0),
    volEth: t.volume24hEth || 0,
    tx24: t.txCount24h || 0,
    ttx: t.totalTxCount || 0,
    pe: t.priceEth || 0,
    pools: t.pools || 1,
    dec: t.decimals || 18,
    ca: t.createdAt || (t.createdAtTime ? Math.floor(new Date(t.createdAtTime).getTime() / 1000) : 0),
    logo: t.logo || null,
    twitter: t.twitter || '', telegram: t.telegram || '', website: t.website || '', discord: t.discord || '',
    creator: t.creator || '',
    athMcapEth: t.athMarketCapEth || 0,
    netBuyEth: t.netBuyAmountEth || 0,
    source: t._source || 'embedded'
  };
}
function normNoxaToken(t) {
  return {
    a: t.address, s: t.symbol, n: t.name, v: t.poolFee ? 'V3' : '',
    p: t.officialPool || '',
    price: (t.priceEth || 0) * ethPriceUsd, priceEth: t.priceEth || 0,
    ch: t.priceChange6hPct || 0,
    mc: (t.marketCapEth || 0) * ethPriceUsd, mcEth: t.marketCapEth || 0,
    liq: ((t.baseTokenReserveEth || 0) + (t.quoteTokenReserveEth || 0)) * ethPriceUsd, liqEth: (t.baseTokenReserveEth || 0) + (t.quoteTokenReserveEth || 0),
    vol: (t.volume24hEth || 0) * ethPriceUsd, volEth: t.volume24hEth || 0,
    tx24: 0, ttx: 0, pe: t.priceEth || 0, pools: 1, dec: t.decimals || 18,
    ca: t.createdAtTime ? Math.floor(new Date(t.createdAtTime).getTime() / 1000) : 0,
    logo: t.logo || null,
    twitter: t.twitter || '', telegram: t.telegram || '', website: t.website || '', discord: t.discord || '',
    creator: t.creator || '', athMcapEth: t.athMarketCapEth || 0, netBuyEth: t.netBuyAmountEth || 0,
    source: 'noxa'
  };
}

/* ===== ON-CHAIN LIQUIDITY (via RPC eth_call) ===== */
async function fetchOnChainLiquidity(token) {
  if (!token || !token.p) return null;
  var cacheKey = token.a;
  if (tokenLiquidity[cacheKey] && (Date.now() - tokenLiquidity[cacheKey].fetched) < 60000) {
    return tokenLiquidity[cacheKey];
  }
  try {
    var poolAddr = token.p;
    var tokenAddr = token.a;
    var isV2Only = token.v && token.v.indexOf('V2') >= 0 && token.v.indexOf('V3') < 0;

    if (!isV2Only) {
      // V3 (or V2+V3 or unknown): compute virtual WETH reserve from slot0 + liquidity
      var slot0Data = await ethCall(poolAddr, '0x3850c7bd'); // slot0()
      var liqData = await ethCall(poolAddr, '0x1a686502');   // liquidity()
      var t0Data = await ethCall(poolAddr, '0x0dfe1681');    // token0()

      if (slot0Data && liqData && t0Data && slot0Data.length >= 130) {
        var sqrtPriceX96 = BigInt('0x' + slot0Data.slice(2, 66));
        var L = BigInt('0x' + liqData.slice(2));
        var token0 = '0x' + t0Data.slice(2).slice(-40).toLowerCase();
        var wethIsToken0 = token0 === WETH_ADDR.toLowerCase();

        if (L > BigInt(0)) {
          var Q96 = BigInt(1) << BigInt(96);
          var WETH_WEI = BigInt('1000000000000000000');
          var virtualWethWei;
          if (wethIsToken0) {
            // WETH = token0: virtual_reserve_x = L * Q96 / sqrtPriceX96
            virtualWethWei = L * Q96 / sqrtPriceX96;
          } else {
            // WETH = token1: virtual_reserve_y = L * sqrtPriceX96 / Q96
            virtualWethWei = L * sqrtPriceX96 / Q96;
          }
          // Convert wei to ETH with 6 decimal precision
          var ethInt = virtualWethWei / WETH_WEI;
          var ethFrac = (virtualWethWei % WETH_WEI) * BigInt(1000000) / WETH_WEI;
          var wethBalance = Number(ethInt) + Number(ethFrac) / 1e6;
          var totalEth = 2 * wethBalance;
          var totalUsd = totalEth * ethPriceUsd;
          var result = {
            tokenReserve: 0,
            ethReserve: totalEth,
            wethReserve: wethBalance,
            poolLiquidity: 0,
            totalEth: totalEth,
            totalUsd: totalUsd,
            fetched: Date.now()
          };
          tokenLiquidity[cacheKey] = result;
          return result;
        } else {
          // L = 0: empty V3 pool
          var result = {
            tokenReserve: 0, ethReserve: 0, poolLiquidity: 0,
            totalEth: 0, totalUsd: 0, fetched: Date.now()
          };
          tokenLiquidity[cacheKey] = result;
          return result;
        }
      }
      // V3 path failed (slot0/liquidity/token0 reverted) — fall through to V2
    }

    // V2: use balanceOf(pair) for WETH reserve
    var liqData2 = await ethCall(poolAddr, '0x1a6865020000000000000000000000000000000000000000000000000000000');
    var poolLiquidity = parseInt(liqData2 || '0x0', 16);
    var balData = await ethCall(tokenAddr, '0x70a08231000000000000000000000000' + poolAddr.slice(2).toLowerCase());
    var tokenBalance = parseInt(balData || '0x0', 16) / Math.pow(10, token.dec || 18);
    var wethBalData = await ethCall(WETH_ADDR, '0x70a08231000000000000000000000000' + poolAddr.slice(2).toLowerCase());
    var wethBalance = parseInt(wethBalData || '0x0', 16) / 1e18;
    var totalEth = wethBalance;
    var totalUsd = totalEth * ethPriceUsd;
    var result = {
      tokenReserve: tokenBalance,
      ethReserve: totalEth,
      wethReserve: wethBalance,
      poolLiquidity: poolLiquidity,
      totalEth: totalEth,
      totalUsd: totalUsd,
      fetched: Date.now()
    };
    tokenLiquidity[cacheKey] = result;
    return result;
  } catch (e) {
    return null;
  }
}

async function fetchOnChainSupply(token) {
  if (!token || !token.a) return null;
  try {
    var data = await ethCall(token.a, '0x18160ddd');
    if (data && data.length > 2) {
      var supplyWei = BigInt('0x' + data.slice(2));
      var dec = BigInt(token.dec || 18);
      var divisor = BigInt(10) ** dec;
      var supply = Number(supplyWei / divisor);
      return supply;
    }
  } catch (e) { }
  return null;
}

async function ethCall(to, data) {
  try {
    var resp = await fetch(RPC, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ jsonrpc: '2.0', method: 'eth_call', params: [{ to: to, data: data }, 'latest'], id: 1 })
    });
    var json = await resp.json();
    return json.result;
  } catch (e) { return null; }
}

/* ===== TOKEN LIST ===== */
function renderTokenList() {
  const list = document.getElementById('tokenList');
  if (!allTokens.length) { list.innerHTML = '<div class="loading-placeholder">No tokens</div>'; return; }
  const search = (document.getElementById('tokenSearch') ? document.getElementById('tokenSearch').value || '' : '').toLowerCase();
  let tokens = allTokens;
  // Block dead/empty tokens
  tokens = tokens.filter(function(t) { return !BLOCKED_TOKENS[(t.a || '').toLowerCase()]; });
  if (search) tokens = tokens.filter(function(t) { return t.s.toLowerCase().includes(search) || (t.n || '').toLowerCase().includes(search) || t.a.toLowerCase().includes(search); });
  if (actFilter === 'graduated') tokens = tokens.filter(function(t) { return (t.mcEth || 0) >= BONDING_TARGET_ETH; });
  else if (actFilter === 'bonding') tokens = tokens.filter(function(t) { return (t.mcEth || 0) < BONDING_TARGET_ETH; });

  if (sortCol) {
    tokens.sort(function(a, b) {
      var va, vb;
      if (sortCol === 'price') { va = a.priceEth || 0; vb = b.priceEth || 0; }
      else if (sortCol === 'change') { va = a.ch || 0; vb = b.ch || 0; }
      else if (sortCol === 'mcap') { va = a.mcEth || 0; vb = b.mcEth || 0; }
      else if (sortCol === 'pair') { va = (a.s || '').toLowerCase(); vb = (b.s || '').toLowerCase(); }
      else { va = 0; vb = 0; }
      if (sortCol === 'pair') return sortDir === 'asc' ? va.localeCompare(vb) : vb.localeCompare(va);
      return sortDir === 'asc' ? va - vb : vb - va;
    });
  } else if (curListTab === 'newest') {
    tokens.sort(function(a, b) { return (b.ca || 0) - (a.ca || 0); });
  } else if (curListTab === 'trending') {
    tokens.sort(function(a, b) { return (b.volEth || 0) - (a.volEth || 0); });
  } else {
    tokens.sort(function(a, b) { return (b.ttx || 0) - (a.ttx || 0); });
  }
  // Pin $HTERM and other pinned tokens to top
  var pinned = tokens.filter(function(t) { return PINNED_TOKENS[(t.a || '').toLowerCase()]; });
  var rest = tokens.filter(function(t) { return !PINNED_TOKENS[(t.a || '').toLowerCase()]; });
  tokens = pinned.concat(rest);

  list.innerHTML = tokens.map(function(t, i) {
    const active = currentToken && currentToken.a === t.a;
    const ch = (t.ch || 0) >= 0 ? 'up' : 'down';
    const isNew = newTokenAddrs.has(t.a);
    const logoUrl = ipfsUrl(t.logo) || MANUAL_LOGOS[t.a.toLowerCase()];
    const avatar = logoUrl ? '<img src="' + logoUrl + '" onerror="this.style.display=\'none\';this.parentElement.textContent=\'' + (t.s || '?').slice(0, 2).toUpperCase() + '\'" />' : (t.s || '?').slice(0, 2).toUpperCase();
    var priceStr = priceUnit === 'usd' ? fmtP(t.priceEth * ethPriceUsd) : t.priceEth.toExponential(4);
    var mcapStr = priceUnit === 'usd' ? fmtC(t.mcEth * ethPriceUsd) : fmtEth(t.mcEth);
    return '<div class="token-item ' + (active ? 'active' : '') + (isNew ? ' new-token' : '') + '" data-addr="' + t.a + '">' +
      '<span class="col-rank">' + (i + 1) + '</span>' +
      '<div class="col-pair"><div class="token-avatar">' + avatar + '</div>' +
      '<div class="token-pair-info"><div class="token-pair-name">' + t.s + (isNew ? '<span class="new-badge">NEW</span>' : '') + '</div>' +
      '<div class="token-pair-sub">' + t.s + '/WETH</div></div></div>' +
      '<span class="col-price">' + priceStr + '</span>' +
      '<span class="col-change ' + ch + '">' + fmtPct(t.ch) + '</span>' +
      '<span class="col-liq">' + mcapStr + '</span></div>';
  }).join('');
}

/* ===== SELECT TOKEN ===== */
function selectToken(token) {
  if (BLOCKED_TOKENS[(token.a || '').toLowerCase()]) return;
  HT.state.requestId++;
  if (HT.controller) HT.controller.abort();
  HT.controller = new AbortController();

  // Atomic pair switch
  const addr = token.a;
  const rid = HT.state.requestId;
  dispatch({ type: 'SELECT_PAIR', address: addr });

  currentToken = token; // compat — 49 refs still use this
  // Override website from MANUAL_SITES if available
  var ms = MANUAL_SITES[(token.a || '').toLowerCase()];
  if (ms) currentToken.website = ms;

  // Refresh on-chain liquidity for this token
  fetchOnChainLiquidity(token).then(function(liq) {
    if (liq && liq.ethReserve > 0) {
      token.liqEth = liq.ethReserve;
      token.liq = liq.totalUsd;
      token._liqOnChainAt = Date.now();
      updateTokenHeader();
      updateSwapPanel();
      updateRightPanel();
      renderTokenList();
    }
  });

  // Fetch on-chain total supply
  fetchOnChainSupply(token).then(function(supply) {
    if (supply && supply > 0) {
      token.supply = supply;
      updateRightPanel();
    }
  });

  renderTokenList();
  updateTokenHeader();
  updateRightPanel();

  // Preload default + most-used timeframes
  loadTimeframes(addr, rid);

  loadTabData(rid);

  // Clear old timer
  if (window.tradeRefreshTimer) clearInterval(window.tradeRefreshTimer);
  window.tradeRefreshTimer = setInterval(function() {
    if (HT.state.currentPairAddress === addr && curTab === 'transactions') {
      loadTabData(HT.state.requestId);
    }
  }, 15000);
}

async function loadTimeframes(addr, rid) {
  // Preload current timeframe FIRST
  var defaultTf = HT.state.timeframe || '1h';
  await fetchAndStoreCandles(addr, defaultTf, rid);

  // Then most-used timeframes
  var preloadTfs = ['5m', '15m', '1m'].filter(function(tf) { return tf !== defaultTf; });
  for (var i = 0; i < preloadTfs.length; i++) {
    await fetchAndStoreCandles(addr, preloadTfs[i], rid);
  }

  // Lazy load the rest
  var allTfs = ['1m', '5m', '15m', '1h', '4h', '1d'];
  for (var i = 0; i < allTfs.length; i++) {
    if (allTfs[i] !== defaultTf && preloadTfs.indexOf(allTfs[i]) === -1) {
      fetchAndStoreCandles(addr, allTfs[i], rid);
    }
  }

  // Render with the current timeframe
  if (rid === HT.state.requestId && addr === HT.state.currentPairAddress) {
    renderCandlesToChart();
  }
}

async function fetchAndStoreCandles(addr, tf, rid) {
  try {
    const candles = await fetchCandles(addr, tf);
    if (rid !== HT.state.requestId) return;
    if (addr !== HT.state.currentPairAddress) return;
    dispatch({ type: 'SET_CANDLES', timeframe: tf, data: candles });
  } catch (e) { /* ignore stale */ }
}

function renderCandlesToChart() {
  // Renders the current timeframe's candles to the chart
  var cd = HT.state.candles[HT.state.timeframe];
  if (!cd.length) {
    document.getElementById('chartLoading').textContent = 'No chart data for this token';
    document.getElementById('chartLoading').style.display = 'block';
    if (chart) { chart.remove(); chart = null; }
    return;
  }
  document.getElementById('chartLoading').style.display = 'none';

  var convertFactor = priceUnit === 'usd' ? ethPriceUsd : 1;
  if (chart) { chart.remove(); chart = null; mainS = volS = null; ma7S = ma25S = ma59S = null; bU = bM = bL = null; }
  chart = LightweightCharts.createChart(document.getElementById('chartContainer'), {
    layout: { background: { color: '#0a0e12' }, textColor: '#a8b4c8', fontSize: 11, fontFamily: "'Spline Sans Mono', monospace" },
    grid: { vertLines: { color: 'rgba(26,32,48,0.4)' }, horzLines: { color: 'rgba(26,32,48,0.4)' } },
    crosshair: { mode: 1, vertLine: { color: '#232c3a', width: 1, style: 3 }, horzLine: { color: '#232c3a', width: 1, style: 3 } },
    rightPriceScale: { borderColor: '#1a2030', scaleMargins: { top: 0.05, bottom: 0.18 }, mode: HT.state.scaleMode === 'lin' ? 0 : 1 },
    localization: { priceFormatter: function(p) {
      var a = Math.abs(p);
      if (a >= 1000) return p.toFixed(2);
      if (a >= 1) return p.toFixed(2);
      if (a >= 0.01) return p.toFixed(4);
      if (a >= 0.000001) return p.toFixed(8).replace(/0+$/, '').replace(/\.$/, '');
      return p.toExponential(2);
    } },
    timeScale: { borderColor: '#1a2030', timeVisible: true, secondsVisible: false, barSpacing: ({'1m':4,'5m':5,'15m':6,'1h':8,'4h':9,'1d':10})[HT.state.timeframe] || 10 },
    width: document.getElementById('chartContainer').clientWidth || 600,
    height: document.getElementById('chartContainer').clientHeight || 400,
  });
  var ro = new ResizeObserver(function() { if (chart && document.getElementById('chartContainer').clientWidth > 0) chart.applyOptions({ width: document.getElementById('chartContainer').clientWidth, height: document.getElementById('chartContainer').clientHeight }); });
  ro.observe(document.getElementById('chartContainer'));
  // Inherit previous close as open so gaps become visible candle bodies
  for (var i = 1; i < cd.length; i++) { cd[i].open = cd[i-1].close; }
  var formatted = cd.map(function(c) { return { time: c.time, open: c.open * convertFactor, high: c.high * convertFactor, low: c.low * convertFactor, close: c.close * convertFactor }; });
  var vd = cd.map(function(c) { return { time: c.time, value: (c.volume || 0) * (priceUnit === 'usd' ? ethPriceUsd : 1), color: c.close >= c.open ? 'rgba(23,186,119,0.35)' : 'rgba(237,75,88,0.35)' }; });
  var minPrice = Infinity;
  for (var i = 0; i < formatted.length; i++) { if (formatted[i].close > 0 && formatted[i].close < minPrice) minPrice = formatted[i].close; }
  var precision = 2, minMove = 0.01;
  if (minPrice < 0.000001) { precision = 9; minMove = 0.000000001; }
  else if (minPrice < 0.00001) { precision = 8; minMove = 0.00000001; }
  else if (minPrice < 0.0001) { precision = 7; minMove = 0.0000001; }
  else if (minPrice < 0.001) { precision = 6; minMove = 0.000001; }
  else if (minPrice < 0.01) { precision = 5; minMove = 0.00001; }
  else if (minPrice < 1) { precision = 4; minMove = 0.0001; }
  createMainSeries(formatted, precision, minMove);
  if (inds.volume) {
    volS = chart.addHistogramSeries({ priceFormat: { type: 'volume' }, priceScaleId: 'vol' });
    volS.priceScale().applyOptions({ scaleMargins: { top: 0.85, bottom: 0 } });
    volS.setData(vd);
  }
  updateInds(formatted);
  // Warning: suggest higher timeframe if >70% candles have sub-0.5% body
  var tinyBody = 0, totalB = formatted.length;
  for (var i = 0; i < totalB; i++) {
    var bodyPct = Math.abs(formatted[i].close - formatted[i].open) / Math.max(formatted[i].open, formatted[i].close, 1e-30);
    if (bodyPct < 0.005) tinyBody++;
  }
  var warnEl = document.getElementById('chartWarning');
  if (tinyBody / totalB > 0.7) {
    var suggest = HT.state.timeframe === '1m' ? '5m' : HT.state.timeframe === '5m' ? '15m' : HT.state.timeframe === '15m' ? '1h' : '4h';
    warnEl.textContent = 'Pergerakan sangat kecil. Coba timeframe ' + suggest + ' untuk visual lebih jelas';
    warnEl.className = 'chart-warning show';
  } else {
    warnEl.className = 'chart-warning';
  }
  // Crosshair tooltip — OHLC panel with smart positioning
  var tooltipEl = document.getElementById('ohlcTooltip');
  var ttLastTime = null;
  chart.subscribeCrosshairMove(function(param) {
    if (!param.point || !param.time || !mainS) {
      tooltipEl.style.display = 'none'; ttLastTime = null; return;
    }
    var sd = param.seriesData.get(mainS);
    if (!sd) { tooltipEl.style.display = 'none'; ttLastTime = null; return; }
    if (ttLastTime === sd.time) return;
    ttLastTime = sd.time;
    if (window._ttHideTimer) { clearTimeout(window._ttHideTimer); window._ttHideTimer = null; }
    var conv = priceUnit === 'usd' ? ethPriceUsd : 1;
    var o = sd.open * conv, h = sd.high * conv, l = sd.low * conv, c = sd.close * conv;
    function fp(v) {
      var a = Math.abs(v);
      if (a >= 1000) return v.toFixed(2);
      if (a >= 1) return v.toFixed(2);
      if (a >= 0.01) return v.toFixed(4);
      if (a >= 0.000001) return v.toFixed(8).replace(/0+$/, '').replace(/\.$/, '');
      return v.toExponential(2);
    }
    var chg = o ? ((c - o) / o * 100) : 0;
    var cc = chg >= 0 ? '#17ba77' : '#ed4b58';
    var ts = new Date(sd.time * 1000);
    var tstr = ts.toLocaleDateString('en-US',{month:'short',day:'numeric'}) + ' ' +
               ts.toLocaleTimeString('en-US',{hour:'2-digit',minute:'2-digit',hour12:false});
    var rawIdx = cd.findIndex(function(c) { return c.time === sd.time; });
    var volStr = '';
    if (rawIdx >= 0 && cd[rawIdx].volume) {
      var v = cd[rawIdx].volume * (priceUnit === 'usd' ? ethPriceUsd : 1);
      volStr = v >= 1000 ? (v/1000).toFixed(1)+'K' : v.toFixed(1);
    }
    tooltipEl.innerHTML =
      '<span class="ohlc-row"><span class="ohlc-label">O</span><span class="ohlc-val">'+fp(o)+'</span></span>'+
      '<span class="ohlc-row"><span class="ohlc-label">H</span><span class="ohlc-val">'+fp(h)+'</span></span>'+
      '<span class="ohlc-row"><span class="ohlc-label">L</span><span class="ohlc-val">'+fp(l)+'</span></span>'+
      '<span class="ohlc-row"><span class="ohlc-label">C</span><span class="ohlc-val">'+fp(c)+'</span></span>'+
      '<span class="ohlc-row ohlc-change" style="color:'+cc+'">'+(chg>=0?'+':'')+chg.toFixed(2)+'%</span>'+
      (volStr ? '<span class="ohlc-row"><span class="ohlc-label">V</span><span class="ohlc-val">'+volStr+'</span></span>' : '')+
      '<span class="ohlc-row ohlc-time">'+tstr+'</span>';
    var xp = param.point.x, yp = param.point.y;
    var cw = document.getElementById('chartContainer').clientWidth, ch = document.getElementById('chartContainer').clientHeight;
    var tw = tooltipEl.offsetWidth || 150, th = tooltipEl.offsetHeight || 120;
    var lx = xp + 14, ty = yp - th/2;
    if (lx + tw > cw - 6) lx = xp - tw - 14;
    if (lx < 2) lx = 2;
    if (ty < 2) ty = 2;
    if (ty + th > ch - 2) ty = ch - th - 2;
    tooltipEl.style.left = lx + 'px';
    tooltipEl.style.top = ty + 'px';
    tooltipEl.style.display = 'block';
  });
  // Default view: last ~60 candles (user can scroll to see full history)
  var total = cd.length;
  var fromIdx = Math.max(0, total - 60);
  chart.timeScale().setVisibleLogicalRange({ from: fromIdx - 0.5, to: total - 0.5 });
}

function updateTokenHeader() {
  if (!currentToken) return;
  document.getElementById('pairBase').textContent = currentToken.s;
  document.getElementById('pairVersion').textContent = currentToken.v || '';
  // Price from SSOT — priceCache[ticker] takes priority over token property
  var addr = currentToken.a;
  var px = HT.state.priceCache[addr];
  var priceEth = px ? px.eth : (currentToken.priceEth || 0);
  if (priceUnit === 'usd') {
    document.getElementById('pairPrice').textContent = fmtP(priceEth * ethPriceUsd);
  } else {
    document.getElementById('pairPrice').textContent = priceEth.toExponential(4) + ' ETH';
  }
  var el = document.getElementById('pairChange');
  el.textContent = fmtPct(currentToken.ch);
  el.className = 'pair-change ' + (currentToken.ch >= 0 ? 'up' : 'down');
}

/* ===== CHART DATA FETCH ===== */
async function fetchCandles(addr, interval) {
  // Returns candles as objects: { time, open, high, low, close, volume, trades }
  try {
    var myResp = await fetch(MY_API + '/ohlc?address=' + encodeURIComponent(addr) + '&interval=' + interval, { cache: 'no-store', headers: {'X-API-Key': API_KEY} });
    if (myResp.ok) {
      var myJson = await myResp.json();
      if (myJson.success && myJson.data.length) {
        return myJson.data.map(function(c) {
          return { time: Math.floor(new Date(c.bucketStart).getTime() / 1000), open: c.open, high: c.high, low: c.low, close: c.close, volume: c.volumeEth, trades: c.trades };
        });
      }
    }
  } catch (e) { }
  // Noxa fallback
  try {
    var resp = await fetch(NOXA_API + '/v1/' + NOXA_CHAIN + '/token/' + addr + '/ohlc?interval=' + interval, { cache: 'no-store' });
    if (resp.ok) {
      var data = await resp.json();
      if (Array.isArray(data) && data.length) {
        return data.map(function(c) {
          return { time: Math.floor(new Date(c.bucketStart).getTime() / 1000), open: c.open, high: c.high, low: c.low, close: c.close, volume: c.volumeEth, trades: c.trades };
        });
      }
    }
  } catch (e) { }
  // Fallback 1: embedded D with exact interval
  if (D.candles && D.candles[addr] && D.candles[addr][interval] && D.candles[addr][interval].length) {
    var ethP = D.eth || 1650;
    return D.candles[addr][interval].map(function(c) {
      return { time: c[0], open: c[1] / ethP, high: c[2] / ethP, low: c[3] / ethP, close: c[4] / ethP, volume: c[5] || 0, trades: c[6] || 0 };
    });
  }
  // Fallback 2: embedded D with 1h interval
  if (interval !== '1h' && D.candles && D.candles[addr] && D.candles[addr]['1h'] && D.candles[addr]['1h'].length) {
    var ethP2 = D.eth || 1650;
    return D.candles[addr]['1h'].map(function(c) {
      return { time: c[0], open: c[1] / ethP2, high: c[2] / ethP2, low: c[3] / ethP2, close: c[4] / ethP2, volume: c[5] || 0, trades: c[6] || 0 };
    });
  }
  return [];
}

async function fetchTrades(addr) {
  // TEMP: Noxa first (fresh data), backend fallback (stale until RPC restored)
  // Returns array format: [timestamp, side, tokenAmount, ethAmount, priceEth, txHash, sender]
  try {
    var resp = await fetch(NOXA_API + '/v1/' + NOXA_CHAIN + '/token/' + addr + '/swaps?limit=50', { cache: 'no-store' });
    if (resp.ok) {
      var data = await resp.json();
      var swaps = data.swaps || data.data || [];
      if (swaps.length) {
        return swaps.map(function(s) {
          return [
            Math.floor(new Date(s.block_timestamp || s.timestamp).getTime() / 1000),
            (s.side || 'buy').toLowerCase(),
            s.amount_token || parseFloat(s.tokenAmount || 0) / 1e18,
            s.amount_eth || s.ethAmount || 0,
            s.price_eth || s.priceEth || 0,
            s.transaction_hash || s.txHash || '',
            s.sender || ''
          ];
        });
      }
    }
  } catch (e) { console.error('Noxa error for trades:', e); }
  // Fallback to our backend
  try {
    var my_resp = await fetch(MY_API + '/swaps?address=' + encodeURIComponent(addr) + '&limit=50', { headers: {'X-API-Key': API_KEY} });
    if (my_resp.ok) {
      var my_result = await my_resp.json();
      if (my_result.success && my_result.data.length) {
        return my_result.data.map(function(s) {
          return [
            Math.floor(new Date(s.block_timestamp).getTime() / 1000),
            (s.side || 'buy').toLowerCase(),
            s.amount_token || 0,
            s.amount_eth || 0,
            s.price_eth || 0,
            s.transaction_hash || '',
            s.trader || s.recipient || s.sender || ''
          ];
        });
      }
    }
  } catch (e) { console.error('My API error for trades:', e); }
  return [];
}

/* ===== CHART ===== */
async function loadChart() {
  if (!currentToken) return;
  const _rid = HT.state.requestId;
  document.getElementById('chartLoading').style.display = 'block';
  document.getElementById('chartLoading').textContent = 'Loading chart...';
  
  // If candles for current timeframe not cached, fetch them
  if (!HT.state.candles[HT.state.timeframe].length) {
    await fetchAndStoreCandles(currentToken.a, HT.state.timeframe, _rid);
  }
  
  if (_rid !== HT.state.requestId) return;
  if (currentToken.a !== HT.state.currentPairAddress) return;
  renderCandlesToChart();
}

function createMainSeries(cd, precision, minMove) {
  var up = '#17ba77', dn = '#ed4b58';
  var pf = { type: 'price', precision: precision, minMove: minMove };
  if (curType === 'candle') { mainS = chart.addCandlestickSeries({ upColor: up, downColor: dn, borderUpColor: up, borderDownColor: dn, wickUpColor: up, wickDownColor: dn, priceFormat: pf }); mainS.setData(cd); }
  else if (curType === 'line') { mainS = chart.addLineSeries({ color: '#2dd4bf', lineWidth: 2, priceFormat: pf }); mainS.setData(cd.map(function(c) { return { time: c.time, value: c.close }; })); }
  else if (curType === 'area') { mainS = chart.addAreaSeries({ lineColor: '#2dd4bf', topColor: 'rgba(45,212,191,0.25)', bottomColor: 'rgba(45,212,191,0.02)', lineWidth: 2, priceFormat: pf }); mainS.setData(cd.map(function(c) { return { time: c.time, value: c.close }; })); }
  else if (curType === 'baseline') { mainS = chart.addBaselineSeries({ baseValue: { type: 'price', price: cd[0] ? cd[0].close : 0 }, topLineColor: 'rgba(23,186,119,1)', topFillColor1: 'rgba(23,186,119,0.25)', topFillColor2: 'rgba(23,186,119,0.05)', bottomLineColor: 'rgba(237,75,88,1)', bottomFillColor1: 'rgba(237,75,88,0.25)', bottomFillColor2: 'rgba(237,75,88,0.05)', lineWidth: 2, priceFormat: pf }); mainS.setData(cd.map(function(c) { return { time: c.time, value: c.close }; })); }
  else if (curType === 'hollow') { mainS = chart.addCandlestickSeries({ upColor: 'rgba(23,186,119,0.3)', downColor: dn, borderUpColor: up, borderDownColor: dn, wickUpColor: up, wickDownColor: dn, priceFormat: pf }); mainS.setData(cd); }
  else if (curType === 'ha') { mainS = chart.addCandlestickSeries({ upColor: up, downColor: dn, borderUpColor: up, borderDownColor: dn, wickUpColor: up, wickDownColor: dn, priceFormat: pf }); mainS.setData(computeHA(cd)); }
}
function computeHA(c) { if (!c.length) return []; var r = []; var p = null; for (var i = 0; i < c.length; i++) { var x = c[i]; var cl = (x.open + x.high + x.low + x.close) / 4; var o = p ? (p.open + p.close) / 2 : (x.open + x.close) / 2; r.push({ time: x.time, open: o, high: Math.max(x.high, o, cl), low: Math.min(x.low, o, cl), close: cl }); p = r[r.length - 1]; } return r; }
function updateInds(cd) {
  [ma7S, ma25S, ma59S, bU, bM, bL].forEach(function(s) { if (s) chart.removeSeries(s); });
  ma7S = ma25S = ma59S = null; bU = bM = bL = null;
  if (!cd.length) return;
  if (inds.ma7) { ma7S = chart.addLineSeries({ color: '#e4b51f', lineWidth: 1, priceLineVisible: false, lastValueVisible: false }); ma7S.setData(cMA(cd, 7)); }
  if (inds.ma25) { ma25S = chart.addLineSeries({ color: '#a78bfa', lineWidth: 1, priceLineVisible: false, lastValueVisible: false }); ma25S.setData(cMA(cd, 25)); }
  if (inds.ma59) { ma59S = chart.addLineSeries({ color: '#4a9eff', lineWidth: 1, priceLineVisible: false, lastValueVisible: false }); ma59S.setData(cMA(cd, 59)); }
  if (inds.boll) { var b = cBoll(cd, 20, 2); bU = chart.addLineSeries({ color: 'rgba(74,158,255,0.5)', lineWidth: 1, priceLineVisible: false, lastValueVisible: false }); bM = chart.addLineSeries({ color: 'rgba(74,158,255,0.3)', lineWidth: 1, priceLineVisible: false, lastValueVisible: false, lineStyle: 2 }); bL = chart.addLineSeries({ color: 'rgba(74,158,255,0.5)', lineWidth: 1, priceLineVisible: false, lastValueVisible: false }); bU.setData(b.u); bM.setData(b.m); bL.setData(b.l); }
}
function cMA(d, p) { var r = []; for (var i = p - 1; i < d.length; i++) { var s = 0; for (var j = 0; j < p; j++) s += d[i - j].close; r.push({ time: d[i].time, value: s / p }); } return r; }
function cBoll(d, p, m) { var mid = [], up = [], lo = []; for (var i = p - 1; i < d.length; i++) { var s = 0; for (var j = 0; j < p; j++) s += d[i - j].close; var v = s / p; var vr = 0; for (var j = 0; j < p; j++) vr += Math.pow(d[i - j].close - v, 2); var sd = Math.sqrt(vr / p); mid.push({ time: d[i].time, value: v }); up.push({ time: d[i].time, value: v + m * sd }); lo.push({ time: d[i].time, value: v - m * sd }); } return { m: mid, u: up, l: lo }; }

/* ===== TAB DATA ===== */
async function loadTabData(rid) {
  if (!currentToken) return;
  var txnHdr = document.getElementById('txnHeader');
  if (txnHdr) txnHdr.style.display = curTab === 'transactions' ? '' : 'none';
  var tradeFilter = document.getElementById('tradeFilter');
  if (tradeFilter) tradeFilter.style.display = curTab === 'transactions' ? '' : 'none';
  const _rid = rid || HT.state.requestId;
  var addr = currentToken.a;
  if (curTab === 'transactions') {
    var trades = await fetchTrades(currentToken.a);
    // Pair lock
    if (_rid !== HT.state.requestId) return;
    if (currentToken.a !== HT.state.currentPairAddress) return;
    dispatch({ type: 'SET_TRADES', data: trades });
    // Populate priceCache from first trade
    if (trades.length && addr) {
      dispatch({ type: 'SET_PRICE', address: addr, priceEth: trades[0][4] || 0, updatedAt: trades[0][0] || Date.now()/1000 });
    }
    if (curFilter !== 'all') trades = trades.filter(function(t) { return t[1] === curFilter.toLowerCase(); });
    renderTrades(trades);
  } else if (curTab === 'toptraders') renderTopTraders(await fetchTrades(currentToken.a));
  else if (curTab === 'holders') renderHolders(currentToken);
  else if (curTab === 'portfolio') { fetchPortfolio(window.userAccount).then(function() { renderPortfolio(); }); }
  else if (curTab === 'info') renderInfo();
}

function renderTrades(trades) {
  var list = document.getElementById('txnList');
  if (!trades.length) { list.innerHTML = '<div class="loading-placeholder">No transactions for this token</div>'; return; }
  list.innerHTML = trades.map(function(t) {
    var tc = (t[1] === 'buy' || t[1] === 'BUY') ? 'buy' : 'sell';
    var typeLabel = (t[1] === 'buy' || t[1] === 'BUY') ? 'Buy' : 'Sell';
    // t[4] is priceEth — convert based on toggle
    var priceEth = t[4] || 0;
    var priceStr = priceUnit === 'usd' ? fmtP(priceEth * ethPriceUsd) : priceEth.toExponential(4);
    var mcapStr = priceUnit === 'usd' ? fmtC((currentToken ? currentToken.mcEth : 0) * ethPriceUsd) : fmtEth(currentToken ? currentToken.mcEth : 0);
    var usdAmt = t[3] * ethPriceUsd;
    var usdStr = fmtC(usdAmt);
    return '<div class="txn-row">' +
      '<span class="txn-col th-date">' + fmtTm(t[0]) + '</span>' +
      '<span class="txn-col th-type ' + tc + '">' + typeLabel + '</span>' +
      '<span class="txn-col th-token-amt">' + fmtT(t[2]) + ' ' + (currentToken ? currentToken.s : '') + '</span>' +
      '<span class="txn-col th-eth-amt">' + fmtE(t[3]) + ' ETH</span>' +
      '<span class="txn-col th-usd-amt">' + usdStr + '</span>' +
      '<span class="txn-col th-price">' + priceStr + '</span>' +
      '<span class="txn-col th-mcap">' + mcapStr + '</span>' +
      '<span class="txn-col th-tx"><a href="' + EXPLORER + '/tx/' + t[5] + '" target="_blank" rel="noopener">\u2197</a></span></div>';
  }).join('');
}

function renderTopTraders(trades) {
  var list = document.getElementById('txnList');
  if (!trades.length) { list.innerHTML = '<div class="loading-placeholder">No trader data for this token</div>'; return; }
  var traders = {};
  for (var i = 0; i < trades.length; i++) {
    var t = trades[i];
    var m = t[6] || 'unknown';
    var side = (t[1] === 'buy' || t[1] === 'BUY') ? 'buy' : 'sell';
    if (!traders[m]) traders[m] = { addr: m, buys: 0, sells: 0, volEth: 0, tBought: 0, tSold: 0 };
    if (side === 'buy') { traders[m].buys++; traders[m].volEth += t[3]; traders[m].tBought += t[2]; }
    else { traders[m].sells++; traders[m].volEth += t[3]; traders[m].tSold += t[2]; }
  }
  var sorted = Object.values(traders).sort(function(a, b) { return b.volEth - a.volEth; }).slice(0, 50);
  list.innerHTML = '<div class="txn-header" style="border-bottom:1px solid var(--border)">' +
    '<span class="txn-col th-date" style="width:40px">#</span>' +
    '<span class="txn-col th-type" style="width:130px">Trader</span>' +
    '<span class="txn-col th-token-amt">B / S</span>' +
    '<span class="txn-col th-eth-amt">Vol ETH</span>' +
    '<span class="txn-col th-price">PnL Est</span>' +
    '<span class="txn-col th-tx">Tx</span></div>' + sorted.map(function(t, i) {
    var net = t.tBought - t.tSold;
    var pnl = net * (currentToken ? currentToken.priceEth : 0);
    return '<div class="txn-row">' +
      '<span class="txn-col th-date" style="width:40px">' + (i + 1) + '</span>' +
      '<span class="txn-col th-type" style="width:130px;color:#60a5fa;font-weight:500">' + sA(t.addr) + '</span>' +
      '<span class="txn-col th-token-amt"><span style="color:#2dd4bf">' + t.buys + 'B</span> / <span style="color:#f87171">' + t.sells + 'S</span></span>' +
      '<span class="txn-col th-eth-amt">' + fmtE(t.volEth) + '</span>' +
      '<span class="txn-col th-price ' + (pnl >= 0 ? 'up' : 'down') + '">' + (pnl >= 0 ? '+' : '') + fmtE(Math.abs(pnl)) + '</span>' +
      '<span class="txn-col th-tx"><a href="' + EXPLORER + '/address/' + t.addr + '" target="_blank" rel="noopener">\u2197</a></span></div>';
  }).join('');
}

async function renderHolders(token) {
  var list = document.getElementById('txnList');
  if (!token || !token.a) { list.innerHTML = '<div class="loading-placeholder">No token selected</div>'; return; }
  list.innerHTML = '<div class="loading-placeholder">Loading on-chain holders...</div>';

  var TRANSFER_TOPIC = '0xddf252ad1be2c89b69c2b068fc378daa952ba7f163c4a11628f55a4df523b3ef';
  var ZERO_ADDR = '0x0000000000000000000000000000000000000000';
  var dec = token.dec || 18;

  try {
    var resp = await fetch(RPC, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ jsonrpc: '2.0', id: 1, method: 'eth_getLogs', params: [{ fromBlock: '0x0', toBlock: 'latest', address: token.a, topics: [TRANSFER_TOPIC] }] })
    });
    var data = await resp.json();
    var logs = data.result || [];

    if (!logs.length) { list.innerHTML = '<div class="loading-placeholder">No Transfer events found</div>'; return; }

    var holders = {};
    for (var i = 0; i < logs.length; i++) {
      var fr = '0x' + logs[i].topics[1].slice(26);
      var to = '0x' + logs[i].topics[2].slice(26);
      var val = logs[i].data && logs[i].data !== '0x' ? Number(BigInt(logs[i].data)) / Math.pow(10, dec) : 0;
      if (fr.toLowerCase() !== ZERO_ADDR) { holders[fr.toLowerCase()] = (holders[fr.toLowerCase()] || 0) - val; }
      holders[to.toLowerCase()] = (holders[to.toLowerCase()] || 0) + val;
    }

    var active = Object.entries(holders).filter(function(e) { return e[1] > 0; }).sort(function(a, b) { return b[1] - a[1]; }).slice(0, 50);
    var totalSupply = 0;
    for (var i = 0; i < active.length; i++) totalSupply += active[i][1];
    var totalHolders = Object.values(holders).filter(function(v) { return v > 0; }).length;

    if (!active.length) { list.innerHTML = '<div class="loading-placeholder">No holders with positive balance</div>'; return; }

    var header = '<div class="txn-header" style="border-bottom:1px solid var(--border)">' +
      '<span class="txn-col th-date" style="width:30px">#</span>' +
      '<span class="txn-col th-type" style="width:120px">Holder</span>' +
      '<span class="txn-col th-token-amt">Balance</span>' +
      '<span class="txn-col th-eth-amt">Pct</span>' +
      '<span class="txn-col th-price">Value</span>' +
      '<span class="txn-col th-tx">Tx</span></div>';

    var rows = active.map(function(e, i) {
      var addr = e[0], bal = e[1];
      var pct = totalSupply > 0 ? (bal / totalSupply * 100).toFixed(1) : '0.0';
      var val = bal * (token.priceEth || 0);
      var valStr = priceUnit === 'usd' ? fmtC(val * ethPriceUsd) : fmtE(val) + ' ETH';
      return '<div class="txn-row">' +
        '<span class="txn-col th-date" style="width:30px">' + (i + 1) + '</span>' +
        '<span class="txn-col th-type" style="width:120px;color:#60a5fa;font-weight:500">' + sA(addr) + '</span>' +
        '<span class="txn-col th-token-amt">' + fmtN(bal, 0) + '</span>' +
        '<span class="txn-col th-eth-amt">' + pct + '%</span>' +
        '<span class="txn-col th-price">' + valStr + '</span>' +
        '<span class="txn-col th-tx"><a href="' + EXPLORER + '/address/' + addr + '" target="_blank" rel="noopener">\u2197</a></span></div>';
    }).join('');

    var summary = '<div class="loading-placeholder" style="padding:8px 16px;text-align:left;font-size:10px;color:var(--text-dim)">On-chain \u00b7 ' + totalHolders + ' holders \u00b7 ' + logs.length + ' transfers scanned \u00b7 Top 50 shown</div>';

    list.innerHTML = header + rows + summary;
  } catch (e) {
    list.innerHTML = '<div class="loading-placeholder">Failed to load holders: ' + (e.message || 'RPC error') + '</div>';
  }
}

