  document.getElementById('secAth').textContent = fmtEth(t.athMcapEth || 0) + ' ETH';
  document.getElementById('secCreated').textContent = t.ca ? fmtTm(t.ca) : '\u2014';
  document.getElementById('descText').textContent = (t.n || t.s) + ' on Robinhood L2.';
  document.getElementById('descTags').innerHTML = '<span class="desc-tag">' + ((t.mcEth || 0) >= BONDING_TARGET_ETH ? 'Graduated' : 'Bonding') + '</span><span class="desc-tag">Uniswap V3</span><span class="desc-tag">Robinhood L2</span>' + (t.source === 'noxa' ? '<span class="desc-tag">Live</span>' : '');

  var socials = '';
  if (t.twitter) socials += '<a class="social-link" href="' + t.twitter + '" target="_blank" rel="noopener">X</a>';
  if (t.telegram) socials += '<a class="social-link" href="' + t.telegram + '" target="_blank" rel="noopener">TG</a>';
  if (t.website) socials += '<a class="social-link" href="' + t.website + '" target="_blank" rel="noopener">Web</a>';
  if (t.discord) socials += '<a class="social-link" href="' + t.discord + '" target="_blank" rel="noopener">DC</a>';
  document.getElementById('socialLinks').innerHTML = socials;

  document.getElementById('contractPool').textContent = sA(t.p);
