/* ===== INIT ===== */
function init() {
  ethPriceUsd = D.eth || 1650;
  document.getElementById('ethPriceTop').textContent = '$' + ethPriceUsd.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
  allTokens = (D.tokens || []).map(function(t) { t._source = 'embedded'; return normToken(t); });
  // Ensure $HTERM always exists in token list
  (function() {
    var htermAddr = '0x70e2dfbb4d3fe46d16db79a103d060c904c1e14c';
    if (!allTokens.find(function(t) { return t.a === htermAddr; })) {
      allTokens.push({ a: htermAddr, s: 'HTERM', n: 'OWL IN HOOD', dec: 18, v: 'V3', p: '0x5d58b7aa532cb88762f254dcfc6e363e65070af3', pools: 1, priceEth: 0, price: 0, ch: 0, mcEth: 0, mc: 0, liqEth: 0, liq: 0, volEth: 0, vol: 0, tx24: 0, ttx: 0, ca: Date.now() / 1000, source: 'hardcoded' });
    }
  })();
  knownAddrs = new Set(allTokens.map(function(t) { return t.a; }));
  updateStatus();
  document.getElementById('sbTabAll').textContent = 'ALL (' + allTokens.length + ')';
  renderTokenList();
  if (allTokens.length > 0) {
    // Default to $HTERM if available
    var def = allTokens.find(function(t) { return (t.a || '').toLowerCase() === DEFAULT_TOKEN_ADDR; });
    if (def) { selectToken(def); }
    else {
      var withCandles = allTokens.filter(function(t) { return D.candles && D.candles[t.a] && D.candles[t.a]['1h'] && D.candles[t.a]['1h'].length > 0; });
      var sorted = allTokens.filter(function(t) { return (t.volEth || 0) > 0.1; }).sort(function(a, b) { return (b.mcEth || 0) - (a.mcEth || 0); });
      var first = (withCandles.length > 0 ? withCandles : allTokens)[0];
      var bestMatch = null;
      for (var i = 0; i < sorted.length; i++) {
        if (D.candles && D.candles[sorted[i].a] && D.candles[sorted[i].a]['1h'] && D.candles[sorted[i].a]['1h'].length > 0) { bestMatch = sorted[i]; break; }
      }
      selectToken(bestMatch || first);
    }
  }
  fetchEthPrice();
  mergeOurPrices();
  pollNewTokens();
  // Token list event delegation — 1 listener for all tokens (including new ones)
  document.getElementById('tokenList').addEventListener('click', function(e) {
    var row = e.target.closest('.token-item');
    if (!row) return;
    var addr = row.dataset.addr;
    var t = allTokens.find(function(x) { return x.a === addr; });
    if (t) selectToken(t);
  });
  // Init OHLC tooltip — hide on touchend after 300ms
  var tooltipOuter = document.getElementById('ohlcTooltip');
  if (tooltipOuter) {
    document.getElementById('chartContainer').addEventListener('touchend', function() {
      if (window._ttHideTimer) clearTimeout(window._ttHideTimer);
      window._ttHideTimer = setTimeout(function() { tooltipOuter.style.display = 'none'; }, 300);
    });
  }
  pollNewTokens();
  pollTrendingUpdates();
  fetchAllTokenLogos(); // fetch logos for all tokens from noxa
  // NEW: fetch full token list from noxa to fill gaps
  fetchAllNoxaTokens();
  // Override inaccurate scraped createdAt with actual first-swap timestamps from DB
  fetchFirstSwapTimes();
  pollTimer = setInterval(function() {
    pollNewTokens(); pollTrendingUpdates(); mergeOurPrices();
    // Refresh on-chain liquidity for currently selected token (bypass cache)
    if (currentToken && currentToken.p) {
      delete tokenLiquidity[currentToken.a];
      fetchOnChainLiquidity(currentToken).then(function(liq) {
        if (liq && liq.ethReserve > 0) {
          currentToken.liqEth = liq.ethReserve;
          currentToken.liq = liq.totalUsd;
          currentToken._liqOnChainAt = Date.now();
          updateTokenHeader();
          updateSwapPanel();
          updateRightPanel();
        }
      });
      fetchOnChainSupply(currentToken).then(function(supply) {
        if (supply && supply > 0) {
          currentToken.supply = supply;
          updateRightPanel();
        }
      });
    }
    // Refresh portfolio if wallet connected and on portfolio tab
    if (window.userAccount && curTab === 'portfolio') {
      fetchPortfolio(window.userAccount).then(function() { renderPortfolio(); });
    }
  }, 30000);

  // Cleanup on unload
  window.addEventListener('beforeunload', function() {
    if (pollTimer) clearInterval(pollTimer);
  });
}

